import './LinkRouter.scss';

import type { FC } from 'react';
import React from 'react';

import { classNames } from '../../helpers/classnames';
import { Typography } from '../Typography';
import type { LinkRouterProps } from './LinkRouter.types';

/**
 * @deprecated LinkRouter никогда не был готовым к использованию компонентом,
 * но если вы по какой то причине его использовали - больше не используйте.
 * Компонент ссылок реализован как части компонента Typography
 */
export const LinkRouter: FC<LinkRouterProps> = ({ children, href, isActive = false, className }) => (
	<a data-testid="LinkRouter" className="dsb-link-router" href={href}>
		<Typography
			variant={'body3'}
			className={classNames(className, 'dsb-link-router__text', isActive ? 'active-link' : 'inactive-link')}
		>
			{children}
		</Typography>
	</a>
);
